// Turbofan Jet Engine — the front of a high-bypass airliner powerplant.
// BREP showcase: a smooth swept nacelle cowling with a true chamfered intake
// lip, an exact revolved spinner cone, and a ring of fan blades placed with
// BREP.circularPattern. One fused, printable solid; every junction overlaps
// by >= 0.5 units so it welds into a single component.
//
// Reference: high-bypass turbofan (CFM LEAP / GE90 family) — fat rounded
// nacelle cowl, bright chamfered inlet lip, conical white spinner with a
// swept-back nose, and a dense ring of curved fan blades. Built head-on so
// the bladed fan + cowling read clearly in the catalog thumbnail.
//
// Coordinate note: the engine axis is +Y (so the intake faces the catalog
// camera, which looks from -Y). Everything is modeled on the +Z axis first
// then rotated -90deg about X at the end.
const { BREP } = api;

// ---------------------------------------------------------------------------
// 1. NACELLE COWLING — a solid of revolution. The profile is the outer skin
//    of the cowl: a rounded fat lip at the front (intake), a bulging belly,
//    and a taper toward the exhaust at the rear. Revolved around Z it becomes
//    the classic high-bypass cowl silhouette. We model it as a thick-walled
//    ring (outer profile minus an inner duct) so the fan sits inside a real
//    intake throat rather than a flat disc.
// ---------------------------------------------------------------------------
// Profile points [radius, z]. z grows from intake (front, z=0) to rear.
// Outer skin sweeps from the lip out to the belly then tapers in.
const cowlOuter = BREP.revolve([
  [16.0,  0.0],   // intake lip inner edge
  [18.5,  1.0],
  [20.0,  3.5],   // belly start
  [20.5,  8.0],   // fattest point
  [20.0, 14.0],
  [18.5, 20.0],
  [16.5, 27.0],   // taper toward exhaust
  [15.0, 33.0],   // exhaust outer rim
  [ 0.0, 33.0],   // close across the back
]);

// Inner duct: the bypass throat bored through the cowl. Slightly flared at
// the intake (matching the lip) and opening to the exhaust at the rear.
const cowlInner = BREP.revolve([
  [13.5,  1.5],   // throat just behind the lip
  [13.0,  6.0],
  [12.8, 14.0],
  [13.0, 22.0],
  [13.5, 31.5],   // exhaust inner rim
  [ 0.0, 31.5],
  [ 0.0,  1.5],
]);

// Hollow cowl = outer skin minus the duct.
let cowl = cowlOuter.cut(cowlInner);

// True chamfer on the intake lip — the bright machined ring at the very
// front of the cowl. The lip rim is the curved edge at z ~= 0, picked by
// minZ near the front face.
cowl = cowl.chamfer(1.2, { maxZ: 0.6 });

const cowling = BREP.label(cowl, 'cowling');

// ---------------------------------------------------------------------------
// 2. SPINNER CONE — the central nose cone the blades mount on. A swept
//    (revolved) ogive cone, not a straight cone, so it reads as the real
//    aerodynamic spinner. Sits at the engine centerline and overlaps the
//    fan hub so the whole thing welds.
// ---------------------------------------------------------------------------
const spinnerCone = BREP.revolve([
  [ 0.0,  -6.0],  // nose tip, poking forward of the intake plane
  [ 1.2,  -4.5],
  [ 2.6,  -2.5],
  [ 4.0,   0.0],
  [ 5.2,   3.0],
  [ 6.0,   6.5],  // base of the spinner
  [ 6.0,   9.0],  // short cylindrical hub skirt
  [ 0.0,   9.0],
]);
const spinner = BREP.label(spinnerCone, 'spinner');

// ---------------------------------------------------------------------------
// 3. FAN HUB — a short disc the blades root into, hidden behind the spinner
//    base. Overlaps the spinner skirt for a clean weld and gives the blades
//    something solid to bite into.
// ---------------------------------------------------------------------------
const hub = BREP.label(
  BREP.cylinder(6.5, 4.0).translate([0, 0, 6.0]),
  'spinner',
);

// ---------------------------------------------------------------------------
// 4. FAN BLADES — a single curved blade, then BREP.circularPattern'd into a
//    full ring. Each blade is a thin box, tapered and twisted (rotated about
//    its own radial axis) into a swept fan-blade shape, with a rounded
//    leading edge via fillet. The root bites into the hub (rMin) and the tip
//    reaches just inside the intake throat (rMax) so the fan fills the inlet.
// ---------------------------------------------------------------------------
// One blade modeled flat along +X (radial), thin in Y (chord faces forward),
// tall-ish in Z is not needed — instead chord runs along Z (axial), so the
// blade is wide in the flow direction like a real fan blade.
const bladeLen = 12.0;   // radial span (root->tip) — long enough to bridge
                         // the hub (r~6) to the cowl throat wall (r~13) so the
                         // fan ring welds the spinner assembly to the cowling.
const bladeChord = 6.5;  // axial width (along Z / flow)
const bladeThick = 1.1;  // thickness

let blade = BREP.box([bladeLen, bladeChord, bladeThick]);
// Round the leading/trailing edges so the blade looks aerofoil-like.
blade = blade.fillet(0.45, { inDirection: [1, 0, 0] });
// Twist the blade about its radial (X) axis to give it pitch.
blade = blade.rotate(28, [1, 0, 0]);
// Lay the blade flat and lift it to the fan plane. Span runs along +Y from
// y~4 (root, biting into the r=6.5 hub) to y~16 (tip, biting into the cowl
// throat wall at r~13). The double overlap (hub + cowl) is what fuses the
// whole engine into ONE solid.
blade = blade
  .rotate(90, [0, 0, 1])              // point the span along +Y for patterning
  .translate([0, 10.0, 5.0]);         // root at r~4, tip at r~16; z=5 fan plane

const blades = BREP.label(
  BREP.circularPattern(blade, 22, { radius: 0 }),
  'blades',
);

// ---------------------------------------------------------------------------
// 5. ASSEMBLE — fuse everything, then orient the engine so the intake faces
//    the catalog camera (-Y). Single fused solid.
// ---------------------------------------------------------------------------
const engine = BREP.fuseAll([
  cowling,
  spinner,
  hub,
  blades,
]);

// Flip 180deg about X so the INTAKE faces up (+Z) — the catalog thumbnail
// camera looks down from an elevated 3/4 angle, so an up-facing intake shows
// the bladed fan + spinner clearly (an up-facing exhaust would just show a
// blank disc). The axis stays on Z, so the coordinate paint selectors
// (paintInCylinder, Z-native) still color the cowling / blades / spinner
// cleanly — the BREP fuseAll scrambles the face-label resolver, so
// paintByLabel is unreliable on this composite.
//
// After this flip: intake/spinner nose at z ~ +6 (top), exhaust at z ~ -33.
return engine.rotate(180, [1, 0, 0]);

